class Solution:
    def longestCommonSubsequence(self, text1, text2):
        from functools import lru_cache
        @lru_cache(maxsize=None)
        def rec(i, j):
            if i == len(text1) or j == len(text2):
                return 0
            if text1[i] == text2[j]:
                return 1 + rec(i + 1, j + 1)
            return max(rec(i + 1, j), rec(i, j + 1))
        return rec(0, 0)

